What does this program print?

```cpp
#include <iostream>

class Widget {
public:
    virtual std::string label() const { return "Widget"; }
    virtual ~Widget() = default;
    friend std::ostream& operator<<(std::ostream& out, const Widget& w) {
        out << w.label(); return out;
    }
};

class Button : public Widget {
public:
    std::string label() const override { return "Button"; }
};

void show(const Widget& w) { std::cout << w << "\n"; }

int main() {
    Button b;
    show(b);
}
```

